exemplos.python:
# Tabela de temperaturas
tabela = [
    [20, 22], # Linha 0
    [18, 15]  # Linha 1
]

# i é o índice da linha, j é o índice da coluna
for i, linha in enumerate(tabela):
    for j, valor in enumerate(linha):
        print(f"Linha {i}, Coluna {j}: Temperatura de {valor}")

pratica_guiada.python:
producao = [
    [100, 100, 100],
    [100, 0, 100],  # A falha está aqui (Linha 1, Coluna 1)
    [100, 100, 100]
]

falhas = 0

for linha_id, semana in enumerate(producao):
    for col_id, pecas in enumerate(semana):

        if pecas == 0:
            print(f"ALERTA CRÍTICO: Falha na Semana {linha_id}, Dia {col_id}!")
            falhas += 1

if falhas == 0:
    print("Produção imaculada.")
else:
    print(f"Total de {falhas} coordenadas reportadas para manutenção.")
